const a = [
  {"id":564,"text":"What is the advantage of fingerprinting?","explanation":null,"reference":"Dow lecture slides: Hematology module, Forensic Medicine lecture slides, Personal Identity III, \"Galtonage or Dactylography I.E. Fingerprints.\"","responses":[{"text":"No special training required","correct":false,"visible":false},{"text":"It is applicable for all people","correct":false,"visible":false},{"text":"It is applicable for all age groups","correct":false,"visible":false},{"text":"It enables absolute identification of an individual","correct":true,"visible":false},{"text":"It does not require any special and expensive instruments","correct":false,"visible":false}]},{"id":979,"text":"Fat is stored in the body in what form?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 188.","responses":[{"text":"Fatty acids","correct":false,"visible":false},{"text":"Ghee","correct":false,"visible":false},{"text":"Wax","correct":false,"visible":false},{"text":"Triglycerides","correct":true,"visible":false},{"text":"Cholesterol","correct":false,"visible":false}]},{"id":1141,"text":"A 23-year-old man presents with pain in his tooth. Upon inspection it is found that pain is in the joint between the tooth and its root. Which joint is this?","explanation":null,"reference":"Juneja P, Munjal A, Hubbard JB. Anatomy, joints. In: StatPearls. StatPearls Publishing; 2023. Accessed March 23, 2023. http://www.ncbi.nlm.nih.gov/books/NBK507893/","responses":[{"text":"Ball-and-socket","correct":false,"visible":false},{"text":"Synchondrosis","correct":false,"visible":false},{"text":"Fibrous","correct":true,"visible":false},{"text":"Hyaline","correct":false,"visible":false},{"text":"Cartilaginous","correct":false,"visible":false}]},{"id":1284,"text":"Which of the following descriptions of the anatomical position is correct?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 5.","responses":[{"text":"Squatting position, both arms by side, and both feet inverted","correct":false,"visible":false},{"text":"Standing straight, both arms abducted, both feet together","correct":false,"visible":false},{"text":"Standing straight, face forward, arms by the side and flexed","correct":false,"visible":false},{"text":"Standing straight, both arms by the side, and both feet together","correct":true,"visible":false},{"text":"Standing straight, both arms by the side and feet everted","correct":false,"visible":false}]},{"id":1499,"text":"Which of the following takes part in the regulation of gene expression?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 36-37.","responses":[{"text":"ssRNA","correct":false,"visible":false},{"text":"miRNA","correct":true,"visible":false},{"text":"rRNA","correct":false,"visible":false},{"text":"mRNA","correct":false,"visible":false},{"text":"tRNA","correct":false,"visible":false}]},{"id":1567,"text":"A dense connective tissue containing bundles of collagen fibers that run parallel to each other and have only fibroblast cells with flattened nuclei in between them. This tissue is present in which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 115.","responses":[{"text":"Capsule","correct":false,"visible":false},{"text":"Tendon","correct":true,"visible":false},{"text":"Adipose tissue","correct":false,"visible":false},{"text":"Ligament","correct":false,"visible":false},{"text":"Aponeurosis","correct":false,"visible":false}]},{"id":1584,"text":"In which of the following conditions does isosmotic volume contraction occur?","explanation":null,"reference":"Tobias A, Ballard BD, Mohiuddin SS. Physiology, water balance. In: StatPearls. StatPearls Publishing; 2022. Accessed April 9, 2022. http://www.ncbi.nlm.nih.gov/books/NBK541059/","responses":[{"text":"Increased antidiuretic hormone (ADH) secretion","correct":false,"visible":false},{"text":"Increased absorption of salts from intestine","correct":false,"visible":false},{"text":"Diarrhea","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Excessive blood loss","correct":false,"visible":false}]},{"id":1617,"text":"What does vomiting lead to?","explanation":null,"reference":"Goren I, Israel A, Carmel-Neiderman NN, et al. Vomiting and hyponatremia are risk factors for worse clinical outcomes among patients hospitalized due to nonsurgical abdominal pain: a retrospective cohort study. Medicine. Published April 2016. https://pubmed.ncbi.nlm.nih.gov/27057886/","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyponatremia","correct":true,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false}]},{"id":10013,"text":"The teacher asks the student to stand in an anatomical position. Which of the following correctly defines his position?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 5.","responses":[{"text":"Face facing forward, standing erect, arms folded, palms facing forward","correct":false,"visible":false},{"text":"Face towards the teacher, standing erect, arms adjacent to sides, palms facing teacher's side","correct":false,"visible":false},{"text":"Face towards the teacher, standing erect, arms adjacent to sides, palms facing backwards","correct":false,"visible":false},{"text":"Face facing forward, standing erect, arms adjacent to sides, palms facing forward","correct":true,"visible":false},{"text":"Face towards the feet, standing erect, arms adjacent to sides, palms facing backwards","correct":false,"visible":false}]},{"id":10045,"text":"Which term refers to the twisting of the foot in the inward direction?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 10.","responses":[{"text":"Eversion","correct":false,"visible":false},{"text":"Dorsiflexion","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Plantarflexion","correct":false,"visible":false},{"text":"Inversion","correct":true,"visible":false}]},{"id":10993,"text":"Okazaki fragments are formed on the ______ strands in the ______ direction.","explanation":"**Okazaki fragments** are formed on the lagging strands in the **5'-3' direction**. The **lagging strand** is synthesized discontinuously in fragments because DNA polymerase can only add nucleotides in the 5'-3' direction. These fragments are later joined together by the enzyme DNA ligase to form a continuous strand. On the other hand, the leading strand is synthesized continuously in the 5'-3' direction.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 419.","responses":[{"text":"Lagging, 3'-5'","correct":false,"visible":false},{"text":"Both same","correct":false,"visible":false},{"text":"Leading, 3'-5'","correct":false,"visible":false},{"text":"Lagging, 5'-3'","correct":true,"visible":false},{"text":"Leading, 5'-3'","correct":false,"visible":false}]},{"id":11522,"text":"Which type of cell change occurs due to long-standing hypertension?","explanation":"Long-standing hypertension typically leads to **hypertrophy** of the affected cells. Hypertrophy refers to an increase in the size of cells, leading to an enlargement of the affected organ. In the context of hypertension, this is commonly seen in the heart, specifically the left ventricle. The increased blood pressure requires the heart to exert more force to pump blood, leading to an enlargement of the cardiac muscle cells (cardiomyocytes) in the left ventricle (left ventricular hypertrophy). This is a compensatory mechanism to deal with the increased workload. \r\n\r\nUnlike hypertrophy, atrophy refers to a decrease in cell size, metaplasia is a change in cell type, hyperplasia refers to an increase in the number of cells, and dysplasia denotes abnormal cell growth and differentiation, which are not directly related to the effects of hypertension.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 493.","responses":[{"text":"Hyperplasia","correct":false,"visible":false},{"text":"Atrophy","correct":false,"visible":false},{"text":"Dysplasia","correct":false,"visible":false},{"text":"Hypertrophy","correct":true,"visible":false},{"text":"Metaplasia","correct":false,"visible":false}]},{"id":11530,"text":"What is the hallmark of irreversible injury?","explanation":"The hallmark of irreversible cell injury is the **loss of the nucleus**. This process occurs through nuclear changes such as pyknosis (nuclear shrinkage and increased basophilia), karyorrhexis (fragmentation of the nucleus), and karyolysis (dissolution of the nuclear structure). These changes signify that the cell can no longer survive or function. Eosinophilia, or increased eosin staining, is a common feature of cell injury but is not specific to irreversible injury. Cellular swelling is an early manifestation of cell injury and is typically reversible. Cellular blebbing is a feature of apoptosis but can also be reversible. Loss of proteins, while indicative of cellular damage, is not a definitive sign of irreversible injury. The irreversible loss of nuclear material is a key indicator that the cell has passed the point of no return and will ultimately lead to cell death.","reference":"(1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 4-5.\r\n\r\n(2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 44.","responses":[{"text":"Loss of proteins","correct":false,"visible":false},{"text":"Cellular swelling","correct":false,"visible":false},{"text":"Loss of nucleus","correct":true,"visible":false},{"text":"Eosinophilia","correct":false,"visible":false},{"text":"Cellular blebbing","correct":false,"visible":false}]},{"id":12475,"text":"While performing an ultrasound, the physician cannot distinguish the embryo craniocaudally. This is most possibly due to the absence of which of the following events?","explanation":"The inability to distinguish the embryo craniocaudally during an ultrasound is most likely due to the absence of the **formation of the primitive streak**.\r\n\r\nThe primitive streak is a crucial structure during embryonic development. It is responsible for initiating gastrulation, a process in which the three germ layers (ectoderm, mesoderm, and endoderm) are formed. The formation of the primitive streak is a fundamental event in establishing the body plan and differentiation of tissues in the developing embryo.\r\n\r\nThe syncytiotrophoblast, trophoblast, and epiblast are important structures in their own right but are not directly related to the craniocaudal distinction during early embryonic ultrasound imaging. On the other hand, the primitive streak's absence can disrupt normal embryonic development, making it challenging to distinguish the embryo's craniocaudal orientation.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 52.","responses":[{"text":"Formation of trophoblast","correct":false,"visible":false},{"text":"Formation of notochord","correct":false,"visible":false},{"text":"Formation of syncytiotrophoblast","correct":false,"visible":false},{"text":"Formation of epiblast","correct":false,"visible":false},{"text":"Formation of primitive streak","correct":true,"visible":false}]},{"id":12476,"text":"A hypertensive patient is given an angiotensin-converting enzyme (ACE) inhibitor that works by lowering Vmax. What type of inhibition is most likely to be involved in this case?","explanation":"In the case of a hypertensive patient being treated with an angiotensin-converting enzyme (ACE) inhibitor that lowers Vmax, the type of inhibition involved is **non-competitive inhibition**.\r\n\r\nNon-competitive inhibition occurs when an inhibitor binds to an enzyme at a site other than the active site, known as an allosteric site. This binding causes a conformational change in the enzyme's structure, rendering it less effective at catalyzing the reaction. Unlike competitive inhibition, non-competitive inhibition doesn't directly compete with the substrate for the active site. Instead, it alters the enzyme's shape and reduces its catalytic activity.","reference":"Delaune KP, Alsayouri K. Physiology, noncompetitive inhibitor. StatPearls. Published 2022. Accessed November 18, 2022. http://www.ncbi.nlm.nih.gov/books/NBK545242/","responses":[{"text":"Non-competitive","correct":true,"visible":false},{"text":"Full agonist","correct":false,"visible":false},{"text":"Allosteric","correct":false,"visible":false},{"text":"Competitive","correct":false,"visible":false},{"text":"Partial agonist","correct":false,"visible":false}]},{"id":12477,"text":"The World Health Organization (WHO) has given the concept of a healthy city. What is the primary objective of this action plan?","explanation":"The primary objective of the World Health Organization's (WHO) concept of a healthy city is to **improve the health and quality of life of urban dwellers**.\r\n\r\nThe concept of a healthy city is a comprehensive approach to urban planning and development that prioritizes the well-being of city residents. It recognizes that cities are complex ecosystems with various social, economic, and environmental factors that can impact the health of their populations. Therefore, the main goal of this action plan is to create urban environments that promote and support the physical, mental, and social health of the people living within them.\r\n\r\nTo achieve this objective, the concept of a healthy city encompasses a range of initiatives, including creating green spaces, ensuring access to healthcare services, promoting healthy lifestyles, improving air and water quality, and fostering community engagement. By making health a central consideration in urban planning and development, the WHO aims to enhance the overall quality of life for urban residents and reduce health disparities within cities.","reference":"Dow lecture slides. Foundation module. Subject: Community medicine. Topic: Healthy City concept, objectives, history, and project. Subtopic: Objective of \"Healthy cities\" Action in EMR.","responses":[{"text":"Start income generation activities","correct":false,"visible":false},{"text":"Stimulate economic development dialogue","correct":false,"visible":false},{"text":"Improve health and quality of life of urban dwellers","correct":true,"visible":false},{"text":"Make people partners","correct":false,"visible":false},{"text":"Social support network","correct":false,"visible":false}]},{"id":12478,"text":"Which of the following parts of the bacterial cell shows the most antigenic variability?","explanation":"Among the parts of a bacterial cell, the **capsule** exhibits the most antigenic variability.\r\n\r\nThe bacterial capsule is a protective layer of polysaccharides or glycoproteins that surrounds the bacterial cell wall. It plays a crucial role in the virulence of certain pathogenic bacteria by providing protection against the host immune system. The capsule's composition can vary greatly among different bacterial strains, and this variation is responsible for the antigenic diversity observed.\r\n\r\nAntigens are molecules that can trigger an immune response. In the case of the bacterial capsule, the differences in its composition give rise to different antigenic profiles. This variability allows bacteria to evade host immune responses, as the host may not recognize the specific antigens presented by the bacterial capsule.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 13, 14.","responses":[{"text":"Spore","correct":false,"visible":false},{"text":"Peptidoglycan","correct":false,"visible":false},{"text":"Capsule","correct":true,"visible":false},{"text":"Slime","correct":false,"visible":false},{"text":"Lipid A of endotoxin","correct":false,"visible":false}]},{"id":12479,"text":"A radiologist observes no line separating the epiphysis and diaphysis on an X-ray because of the complete fusion of bones. What is this joint at the epiphyseal plate called?","explanation":"The joint at the epiphyseal plate where the radiologist observes no line separating the epiphysis and diaphysis on an X-ray due to the complete fusion of bones is called a **primary cartilaginous joint**, also known as a **synchondrosis**.\r\n\r\nIn primary cartilaginous joints, the connecting material between the bones is hyaline cartilage. The epiphyseal plate, which is a layer of hyaline cartilage located near the ends of growing long bones, serves as a temporary joint during the growth and development of the bone. As a person matures, the epiphyseal plate undergoes a process called **ossification** or **closure**, during which the hyaline cartilage is gradually replaced by bone tissue. Once this process is complete, the epiphyseal plate fuses, resulting in a continuous bony structure with no visible line on X-rays. This fusion signifies the end of longitudinal bone growth.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 25, 26.","responses":[{"text":"Symphysis","correct":false,"visible":false},{"text":"Synovial joint","correct":false,"visible":false},{"text":"Primary cartilaginous joint","correct":true,"visible":false},{"text":"Syndesmosis","correct":false,"visible":false},{"text":"Secondary cartilaginous joint","correct":false,"visible":false}]},{"id":12480,"text":"Cerebrosides are composed of which of the following?","explanation":"**Cerebrosides** are glycosphingolipids composed of several components. These lipids are vital constituents of cell membranes, particularly in the nervous system. The main constituents of cerebrosides include **sphingosine, galactose, and fatty acids**, in addition to a central structure known as **ceramide**.\r\n\r\nSphingosine, a long-chain amino alcohol, forms the foundational structure of sphingolipids, including cerebrosides. Galactose, a single sugar molecule, is typically the carbohydrate component found in cerebrosides, distinguishing them from other sphingolipids. Fatty acids are linked to sphingosine, resulting in the formation of ceramide, which serves as the core structure of cerebrosides. These fatty acids can vary in terms of their chain length and saturation.\r\n\r\nCerebrosides are particularly abundant in the myelin sheath surrounding nerve fibers, where they play a crucial role in insulating and safeguarding the nerves. This insulation is essential for the efficient transmission of nerve signals.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 209.","responses":[{"text":"Sphingosine, galactose, fatty acid, and ceramide","correct":true,"visible":false},{"text":"Sphingosine, ceramide, and phosphate","correct":false,"visible":false},{"text":"Fatty acids and ceramide only","correct":false,"visible":false},{"text":"Sphingosine, phosphate, and fatty acid","correct":false,"visible":false},{"text":"Ceramides only","correct":false,"visible":false}]},{"id":12481,"text":"Which of the following is not a component of the Graafian follicle?","explanation":"The **primary oocyte** is not a component of the Graafian follicle.\r\n\r\nThe Graafian follicle, also known as a mature or tertiary follicle, is a crucial structure in the female reproductive system that plays a significant role in ovulation and the release of eggs (oocytes). It undergoes several developmental stages before reaching maturity. The key components of the Graafian follicle include:\r\n\r\n1. **Granulosa Cells:** These are somatic cells that surround the developing oocyte within the follicle. They provide essential support and nutrients to the oocyte as it matures.\r\n\r\n2. **Cumulus Oophorus:** This is a mound of granulosa cells that directly surrounds the oocyte. It plays a crucial role in nourishing and protecting the oocyte during development.\r\n\r\n3. **Zona Pellucida:** This is a glycoprotein-rich membrane that surrounds the oocyte and separates it from the granulosa cells. It is involved in various functions, including fertilization.\r\n\r\n4. **Secondary Oocyte:** The Graafian follicle contains the secondary oocyte, which is the matured form of the primary oocyte. It is arrested in metaphase II of meiosis and is ready for ovulation.\r\n\r\nThe primary oocyte is the stage before the secondary oocyte, and it is typically found in earlier stages of follicular development. It undergoes meiosis to become a secondary oocyte within the Graafian follicle. Once fully matured, the secondary oocyte can be released during ovulation and potentially fertilized by sperm.","reference":"(1) Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 22.\r\n\r\n(2) Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 28, 29.","responses":[{"text":"Secondary oocyte","correct":false,"visible":false},{"text":"Granulosa cells","correct":false,"visible":false},{"text":"Cumulus oophorus","correct":false,"visible":false},{"text":"Zona pellucida","correct":false,"visible":false},{"text":"Primary oocyte","correct":true,"visible":false}]},{"id":12482,"text":"Which of the following structures contains keratin sulfate in abundance?","explanation":"**Cornea** is the structure that contains keratan sulfate in abundance.\r\n\r\nKeratan sulfate is a type of glycosaminoglycan (GAG), which is a long, unbranched polysaccharide molecule found in various connective tissues. Among these tissues, the cornea is known for its high concentration of keratan sulfate.\r\n\r\nThe cornea is the transparent, dome-shaped front surface of the eye, and it plays a crucial role in focusing light onto the retina. To maintain its transparency and mechanical strength, the cornea relies on the presence of keratan sulfate. This GAG contributes to the cornea's ability to withstand external pressure, maintain its shape, and allow light to pass through without distortion.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 159.","responses":[{"text":"Extracellular membrane","correct":false,"visible":false},{"text":"Cardiac muscle","correct":false,"visible":false},{"text":"Hepatocyte","correct":false,"visible":false},{"text":"Cartilage","correct":false,"visible":false},{"text":"Cornea","correct":true,"visible":false}]},{"id":12483,"text":"Which of the following types of cell junctions does not allow passage of extracellular fluid via the paracellular route?","explanation":"Among the various types of cell junctions, **zonula occludens**, also known as **tight junctions**, are the ones that do not allow the passage of extracellular fluid via the paracellular route.\r\n\r\nZonula occludens are specialized junctions found in epithelial and endothelial tissues, where they play a crucial role in creating a barrier that limits the movement of molecules between adjacent cells. These junctions seal the intercellular space and prevent the diffusion of ions, solutes, and extracellular fluids through the gaps between cells. This sealing effect is essential for maintaining the selective permeability of epithelial and endothelial barriers in various tissues, including the intestinal lining and blood-brain barrier.\r\n\r\nIn contrast, other types of cell junctions like desmosomes, gap junctions, macula adherens (adherens junctions), and hemidesmosomes serve different functions, such as providing structural support, allowing communication between cells, and anchoring cells to the extracellular matrix, but they do not create the same impermeable barrier as tight junctions.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 75.","responses":[{"text":"Desmosomes","correct":false,"visible":false},{"text":"Hemidesmosomes","correct":false,"visible":false},{"text":"Zonula occludens","correct":true,"visible":false},{"text":"Macula adherens","correct":false,"visible":false},{"text":"Gap junctions","correct":false,"visible":false}]},{"id":12484,"text":"Which of the following types of muscles is responsible for the dilation and constriction of blood vessels?","explanation":"The type of muscle responsible for the dilation and constriction of blood vessels is **smooth muscle**. \r\n\r\nSmooth muscle is a specialized type of muscle tissue found in the walls of various organs and structures in the body, including blood vessels. It possesses unique properties that make it well-suited for regulating the diameter of blood vessels, a process known as vasomotion. \r\n\r\nThe contraction and relaxation of smooth muscle cells in the walls of blood vessels play a crucial role in controlling blood flow and blood pressure throughout the body. When these smooth muscle cells contract, the blood vessels constrict, reducing blood flow. Conversely, when they relax, the vessels dilate, allowing for increased blood flow.","reference":"Laiq Hussain Siddiqui. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 86.","responses":[{"text":"Cardiac muscle","correct":false,"visible":false},{"text":"Smooth muscle","correct":true,"visible":false},{"text":"Skeletal muscle","correct":false,"visible":false},{"text":"Smooth and skeletal muscle","correct":false,"visible":false},{"text":"Cardiac and smooth muscle","correct":false,"visible":false}]},{"id":12485,"text":"Tendons are classified as what type of connective tissue?","explanation":"Tendons are classified as **dense regular connective tissue.** This categorization is based on the specific characteristics of their structure and function. \r\n\r\nTendons are primarily composed of densely packed collagen fibers that are organized in a parallel fashion. This arrangement gives tendons their unique properties. Their main function is to connect muscles to bones, and they play a crucial role in transmitting the force generated by muscle contractions to the bones, thus enabling the movement of the skeletal system. \r\n\r\nThe dense regular arrangement of collagen fibers in tendons is essential for their function because it provides both strength and flexibility in a specific direction, aligning with the directional force applied by the contracting muscles. In essence, tendons act as strong, cable-like structures that ensure the smooth and efficient transfer of muscular force to produce movement in the body. \r\n\r\nCollagen is the predominant component of tendons, contributing significantly to their tensile strength. This dense and organized collagen fiber arrangement allows tendons to withstand the considerable pulling forces and tension that occur during muscle contractions, ensuring their structural integrity and ability to perform their vital role in the musculoskeletal system.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 115.","responses":[{"text":"Dense irregular connective tissue","correct":false,"visible":false},{"text":"Areolar connective tissue","correct":false,"visible":false},{"text":"Adipose tissue","correct":false,"visible":false},{"text":"Loose connective tissue","correct":false,"visible":false},{"text":"Dense regular connective tissue","correct":true,"visible":false}]},{"id":12486,"text":"A woman presents with an injury to the pubic symphysis after a motorbike accident. The pubic symphysis is a secondary cartilaginous joint. Which of the following is not a characteristic of secondary cartilaginous joints?","explanation":"Secondary cartilaginous joints, such as the pubic symphysis, exhibit several characteristics. However, one characteristic that does not apply to these joints is being \"covered with a synovial membrane.\"\r\n\r\nSecondary cartilaginous joints, also known as symphyses, have the following features:\r\n\r\n1. **United by Fibrocartilage:** Symphyses are formed by the articulation of bones with cartilaginous tissue. This cartilage is fibrocartilage, which provides strength and stability to the joint.\r\n\r\n2. **Also Called Symphysis:** These joints are commonly referred to as symphyses because they involve the fusion of two bones by a pad of fibrocartilage.\r\n\r\n3. **Lies in the Midline of the Body:** Symphyses are typically located in the midline of the body, contributing to the structural integrity of the axial skeleton.\r\n\r\n4. **Slightly Moveable Joint:** While symphyses allow for limited movement, they are considered amphiarthroses, which means they permit slight movement. This characteristic is essential for functions like shock absorption and flexibility.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 26.","responses":[{"text":"Lies in the midline of the body","correct":false,"visible":false},{"text":"Also called symphysis","correct":false,"visible":false},{"text":"Covered with synovial membrane","correct":true,"visible":false},{"text":"Slightly moveable joint","correct":false,"visible":false},{"text":"United by fibrocartilage","correct":false,"visible":false}]},{"id":12487,"text":"Which of the following is the major cation present in extra-cellular fluid (ECF)?","explanation":"The major cation present in the extracellular fluid (ECF) is **Sodium (Na+)**.\r\n\r\nSodium is the primary extracellular cation, meaning it is predominantly found outside the cells. Its concentration in the ECF is tightly regulated by the body because it has a direct impact on blood pressure, nerve function, and muscle contractions.\r\n\r\nOne of its critical functions is to maintain osmotic pressure, which helps regulate the movement of water in and out of cells. Sodium ions work in conjunction with chloride ions (Cl-) and bicarbonate ions (HCO3-) to maintain proper acid-base balance.\r\n\r\nSodium also plays a pivotal role in nerve impulse transmission and muscle contraction. Nerve cells (neurons) rely on sodium channels to generate and transmit electrical signals, while muscle cells need sodium for the initiation of muscle contractions.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 307.","responses":[{"text":"Magnesium","correct":false,"visible":false},{"text":"Iron","correct":false,"visible":false},{"text":"Sodium","correct":true,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false}]},{"id":12488,"text":"Which of the following is the most abundant anion in the intra-cellular fluid?","explanation":"The most abundant anion in the intracellular fluid (ICF) is **phosphate**.\r\n\r\n**Phosphate ions (HPO4^2- and H2PO4^-)** are essential components of cellular structures, particularly nucleic acids (DNA and RNA) and ATP (adenosine triphosphate), the primary energy currency of cells. Phosphate groups are also found in various other molecules involved in intracellular signaling and metabolism.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 307.","responses":[{"text":"Phosphate","correct":true,"visible":false},{"text":"Magnesium","correct":false,"visible":false},{"text":"Chloride","correct":false,"visible":false},{"text":"Bicarbonate","correct":false,"visible":false},{"text":"Sulphates","correct":false,"visible":false}]},{"id":12489,"text":"A tissue is stained with hematoxylin and eosin (H\u0026E) and it is readily stained blue. What does this signify about the tissue?","explanation":"When a tissue stained with hematoxylin and eosin (H\u0026E) readily appears blue, it signifies that the tissue is **basophilic**. \r\n\r\n**Hematoxylin** is a basic dye that has an affinity for acidic structures in cells. It stains nuclei and other acidic structures in shades of blue-purple. Nucleic acids (DNA and RNA) within cell nuclei are acidic due to the phosphate groups in their structure. Therefore, when the tissue takes up hematoxylin, the nuclei and other acidic components appear blue.\r\n\r\n**Eosin**, on the other hand, is an acidic dye that stains basic or alkaline structures in cells. It imparts shades of pink or red to these structures.","reference":"Laiq Hussain Siddiqui. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 3.","responses":[{"text":"Hydrophobic","correct":false,"visible":false},{"text":"Hydrophilic","correct":false,"visible":false},{"text":"Acidophilic","correct":false,"visible":false},{"text":"Carbohydrate rich","correct":false,"visible":false},{"text":"Basophilic","correct":true,"visible":false}]},{"id":12490,"text":"During the posttranscriptional modification of mRNA which of the following is added at the 3' end?","explanation":"During the posttranscriptional modification of mRNA, a **Poly-A tail** is added at the 3' end. This process is known as polyadenylation and is crucial for the stability, transport, and translation of mRNA in eukaryotic cells.\r\n\r\nThe addition of a Poly-A tail involves the enzymatic cleavage of the mRNA transcript at a specific site and the subsequent addition of a string of adenine nucleotides (A's) to the newly formed 3' end.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 442.","responses":[{"text":"Poly-U tail","correct":false,"visible":false},{"text":"Primer","correct":false,"visible":false},{"text":"7-methylguanosine","correct":false,"visible":false},{"text":"Poly-A tail","correct":true,"visible":false},{"text":"GTP-cap","correct":false,"visible":false}]},{"id":12491,"text":"A chromosome has a protein conjugated with which of the following biomolecules?","explanation":null,"reference":"Lieberman M, Swanson TA. BRS: Biochemistry, Molecular Biology, and Genetics. 6th ed. Wolters Kluwer/Lippincott Williams \u0026 Wilkins; 2014: 54.","responses":[{"text":"Nucleotides","correct":false,"visible":false},{"text":"Ribonucleic acid (RNA)","correct":false,"visible":false},{"text":"Histones","correct":false,"visible":false},{"text":"Deoxyribonucleic acid (DNA)","correct":true,"visible":false},{"text":"Nucleosides","correct":false,"visible":false}]},{"id":12492,"text":"A boy fell down while cycling, injured his elbow, and started bleeding. Which of the following types of epithelium is damaged in this case?","explanation":"In the case of a boy who fell while cycling and injured his elbow, resulting in bleeding, the damaged type of epithelium is **stratified squamous keratinized epithelium**.\r\n\r\nStratified squamous keratinized epithelium is a type of tissue that is specifically adapted to protect against mechanical stress and external factors. It is typically found on the skin's surface, especially on the palms of the hands and the soles of the feet. This epithelium is characterized by multiple layers of cells, with the outermost layer composed of flattened, dead cells filled with a tough, waterproof protein called keratin.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 80.","responses":[{"text":"Simple squamous","correct":false,"visible":false},{"text":"Stratified squamous non-keratinized","correct":false,"visible":false},{"text":"Pseudostratified","correct":false,"visible":false},{"text":"Stratified squamous keratinized","correct":true,"visible":false},{"text":"Simple cuboidal","correct":false,"visible":false}]},{"id":12493,"text":"While working in a warehouse a 45-year-old man is struck on the leg by a falling pallet rack. It strikes him on his left leg in the region of his thigh. The skin is not broken. Within 2 days there is a 5 x 7 cm purple color bruise at the site of injury. Which of the following substances has most likely accumulated at the site of injury to produce a yellow-brown color at the site of injury 16 days later?","explanation":"The yellow-brown coloration observed at the site of injury 16 days later is most likely due to the accumulation of **bilirubin**.\r\n\r\nWhen red blood cells are broken down, hemoglobin is released, and it is metabolized to produce biliverdin, which is then converted to bilirubin. Bilirubin is a yellow pigment that can be found in various tissues of the body, including the skin. In the context of a bruise, the initial purple coloration is caused by the accumulation of blood under the skin (hematoma). Over time, the body's natural processes work to break down the components of the trapped blood. Bilirubin is one of the products of this breakdown.\r\n\r\nAs bilirubin accumulates in the healing tissue, it can impart a yellow-brown color to the bruise. This change in color is part of the normal resolution of a bruise as the body gradually reabsorbs and metabolizes the components of the trapped blood.","reference":"(1) Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 193.\r\n(2) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 282.","responses":[{"text":"Melanin","correct":false,"visible":false},{"text":"Bilirubin","correct":true,"visible":false},{"text":"Hemosiderin","correct":false,"visible":false},{"text":"Lipofuscin","correct":false,"visible":false},{"text":"Glycogen","correct":false,"visible":false}]},{"id":12494,"text":"A person raises their foot towards their knee with toes pointing upwards. What is this movement of the foot termed?","explanation":"The movement described, where a person raises their foot towards their knee with their toes pointing upwards, is termed **dorsiflexion**.\r\n\r\n**Dorsiflexion** is the motion that brings the top of the foot closer to the shin or anterior surface of the lower leg. This movement occurs primarily at the ankle joint and is essential for activities such as walking, running, and lifting the toes off the ground. Dorsiflexion is the opposite of plantarflexion, where the toes point downward and the foot is extended away from the shin.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 8, 10.","responses":[{"text":"Inversion","correct":false,"visible":false},{"text":"Dorsiflexion","correct":true,"visible":false},{"text":"Eversion","correct":false,"visible":false},{"text":"Plantarflexion","correct":false,"visible":false},{"text":"Extension","correct":false,"visible":false}]},{"id":12495,"text":"Which of the following statements best describes reposition?","explanation":"**Reposition** is a specific movement in anatomy, and the best description for it is:\r\n\r\n**\"A movement in which the thumb and finger return to the anatomical position after opposition.\"**\r\n\r\nTo understand this movement, it's important to know what opposition is. Opposition is the movement that allows the thumb to touch the tips of the fingers. It's a crucial movement for human dexterity and the ability to grasp objects between the thumb and fingers. After the thumb and fingers have been brought into opposition (touching), reposition refers to the reverse movement, where the thumb and finger return to their natural, relaxed position by moving away from each other.\r\n\r\nThis movement is essential for tasks that require precision, like picking up small objects or manipulating tools. It allows us to use our hands effectively for various activities in daily life.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 11.","responses":[{"text":"A special kind of movement involving circular motion of the thumb","correct":false,"visible":false},{"text":"A movement in which the thumb and finger return to anatomical position after opposition","correct":true,"visible":false},{"text":"A movement involving flexion of arm","correct":false,"visible":false},{"text":"A movement in which thumb touches the tips of fingers","correct":false,"visible":false},{"text":"A movement involving flexion of wrist","correct":false,"visible":false}]},{"id":12640,"text":"What is the function of flagella in bacteria?","explanation":"Flagella in bacterial cells primarily serve the function of **locomotion**. These slender whip-like appendages enable bacteria to move towards favorable environments or away from harmful ones, contributing significantly to their survival and proliferation.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 11.","responses":[{"text":"Acts as sex pilli","correct":false,"visible":false},{"text":"Locomotion","correct":true,"visible":false},{"text":"To obtain nutrient in agar medium","correct":false,"visible":false},{"text":"Reproduction","correct":false,"visible":false},{"text":"Adherence to tissue surface","correct":false,"visible":false}]},{"id":12641,"text":"Which of the following types of RNA exhibits catalytic property?","explanation":"The type of RNA that exhibits catalytic properties is known as **\"Ribozyme.\"** Ribozymes are a special class of RNA molecules that possess enzymatic activity, similar to proteins, and can catalyze specific chemical reactions.\r\n\r\nThe discovery of ribozymes challenged the traditional view that enzymes, which are biological catalysts, are exclusively proteins. Ribozymes have the remarkable ability to accelerate chemical reactions, just like protein enzymes. One well-known example of a ribozyme is the **\"ribozyme RNAse P,\"** which plays a critical role in processing transfer RNA (tRNA) molecules.\r\n\r\nRibozymes are significant in various biological processes, including RNA splicing, where they help remove introns from pre-mRNA molecules during gene expression. These catalytic RNA molecules have opened up new avenues in molecular biology and biotechnology, as they have the potential for therapeutic applications and the design of novel RNA-based catalysts.","reference":"Walter NG, Engelke DR. Ribozymes: Catalytic RNAs that cut things, make things, and do odd and useful jobs. Biologist (London, England). Published October 2002. Accessed November 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3770912/","responses":[{"text":"Ribonuclease","correct":false,"visible":false},{"text":"Ribosome","correct":false,"visible":false},{"text":"Ribonucleotide","correct":false,"visible":false},{"text":"mRNA","correct":false,"visible":false},{"text":"Ribozyme","correct":true,"visible":false}]},{"id":12644,"text":"The part of decidua which lies underneath the implanted embryo is termed as?","explanation":"The part of the decidua that lies directly underneath the implanted embryo is termed **\"Decidua basalis.\"** This region is crucial for the establishment and maintenance of the placenta, which plays a vital role in providing nutrients and oxygen to the growing fetus and removing waste products.\r\n\r\nThe **Decidua parietalis** refers to the portion of the decidua that lines the rest of the uterine cavity not covered by the embryo. \r\n\r\nThe **Fused parietalis and capsularis** describe the region where the decidua parietalis and decidua capsularis come together, enveloping the gestational sac.\r\n\r\nThe **Decidua capsularis** is the part of the decidua that surrounds and initially covers the implanted embryo, providing protection during early stages of development.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 109.","responses":[{"text":"Fused parietalis and basalis","correct":false,"visible":false},{"text":"Decidua basalis","correct":true,"visible":false},{"text":"Decidua parietalis","correct":false,"visible":false},{"text":"Decidua capsularis","correct":false,"visible":false},{"text":"Fused parietalis and capsularis","correct":false,"visible":false}]},{"id":12645,"text":"A 48-year-old man who has a history of chronic alcohol abuse is capable of doing his work just fine. He has had no major illnesses and physical examination reveals no significant findings. Laboratory studies also do not show any significant dysfunction. Which of the following findings are likely to be seen in his liver under light microscope?","explanation":"**Accumulation of large lipid droplets within hepatocytes** is a characteristic finding in chronic alcohol abuse. These droplets represent fat accumulation within liver cells, a condition known as fatty liver or hepatic steatosis. Chronic alcohol consumption can disrupt lipid metabolism and lead to the accumulation of fat within hepatocytes.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 40.","responses":[{"text":"Nuclear changes; karyolysis, pyknosis, karyorrhexis","correct":false,"visible":false},{"text":"Complete destruction of architecture of liver","correct":false,"visible":false},{"text":"Accumulation of large lipid droplets within hepatocytes","correct":true,"visible":false},{"text":"Detachment of polysomes","correct":false,"visible":false},{"text":"Hypertrophy of smooth endoplasmic reticulum","correct":false,"visible":false}]},{"id":12647,"text":"Bacteria that are permanent residents in various parts of the body are known as normal flora. Which of the following statements best describes the colonization of the bacteria?","explanation":"**Colonization** involves the acquisition of new organisms, typically microorganisms such as bacteria and fungi, in a specific anatomical site. This process can occur through various means, such as exposure to environmental sources or contact with individuals carrying these microorganisms. However, these newly acquired organisms are not part of the body's natural or permanent flora.\r\n\r\nThe statement that best describes colonization is  **\"This is the acquisition of new organisms.\"** This process allows for the introduction of potentially beneficial or harmless microorganisms into the body, which can have a role in preventing the colonization of pathogenic organisms and maintaining a healthy microbial balance at various anatomical sites.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 32.","responses":[{"text":"Certain bacteria and fungi which are always present in mouth, colon and vagina","correct":false,"visible":false},{"text":"They are permanent residents","correct":false,"visible":false},{"text":"They provide essential vitamins","correct":false,"visible":false},{"text":"They inhibit pathogenic organism from binding to the epithelial surfaces","correct":false,"visible":false},{"text":"This is the acquisition of new organisms","correct":true,"visible":false}]},{"id":12649,"text":"The normal flora inhibits pathogenic bacteria from binding to the mucosal surfaces of the body. Which of the following statements best describes the mechanism of colonization resistance?","explanation":"The mechanism of colonization resistance, employed by the normal flora of the body, plays a crucial role in inhibiting pathogenic bacteria from binding to mucosal surfaces. This protective mechanism helps maintain the delicate balance of microorganisms in various parts of the body, such as the intestines.\r\n\r\n**The resident bacteria occupy attachment sites on the mucosa**, acting as a barrier to prevent pathogenic bacteria from adhering to the mucosal lining. By occupying these attachment sites, the normal flora effectively competes with potential invaders for space and resources, making it difficult for pathogenic bacteria to establish a foothold.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 27.","responses":[{"text":"Malnourished patients develop vitamin deficiencies due to reduced flora","correct":false,"visible":false},{"text":"Intestinal bacteria provide vitamins B and K","correct":false,"visible":false},{"text":"Normal flora causes disease in immunocompromised patients","correct":false,"visible":false},{"text":"The resident bacteria occupy attachment sites on the mucosa","correct":true,"visible":false},{"text":"Excessive use of antibiotics suppress normal flora","correct":false,"visible":false}]},{"id":12650,"text":"The excessive use of antibiotics can have serious side effects on the body, especially the gastrointestinal tract (GIT). Which organism can lead to the formation of a pseudo-membrane in the GIT due to excessive antibiotic use?","explanation":"Excessive use of antibiotics can disrupt the normal balance of microorganisms in the gastrointestinal tract (GIT), leading to various gastrointestinal issues. One of the concerning consequences of this disruption is the formation of a pseudo-membrane in the GIT, a condition known as **Clostridium difficile** infection (CDI).\r\n\r\n**Clostridium difficile** is a bacterium that can overgrow in the GIT when the normal gut flora is disturbed, often due to antibiotic use. This bacterium produces toxins that can damage the lining of the intestines. In response to this damage, the body may produce a pseudo-membrane made up of inflammatory cells, mucus, and debris. This pseudo-membrane can cover the inner lining of the intestines and cause severe diarrhea, abdominal pain, and other GIT symptoms.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 27.","responses":[{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Streptococci","correct":false,"visible":false},{"text":"Clostridium difficile","correct":true,"visible":false},{"text":"Staphylococci","correct":false,"visible":false},{"text":"Balantidium coli","correct":false,"visible":false}]},{"id":12651,"text":"The presence of a cluster of flagella on a single pole of a bacterial cell is termed?","explanation":"The presence of a cluster of flagella on a single pole of a bacterial cell is termed **lophotrichous**.\r\n\r\nIn bacterial morphology, flagella are the whip-like appendages that allow bacteria to move through their environment. The arrangement of flagella on the bacterial cell surface can vary, and \"lophotrichous\" refers to a specific arrangement where multiple flagella are located at one or both ends of the bacterial cell.\r\n\r\n- **Monotrichous**: This term describes a single flagellum at one end of the bacterium.\r\n- **Bipolar flagella**: In this arrangement, there are flagella at both ends of the bacterial cell.\r\n- **Amphitrichous**: This term is used when there are flagella at both poles (ends) of the bacterium.\r\n- **Petritrichous**: Bacteria with flagella distributed randomly all over their surface.","reference":"Park J, Kim Y, Lee W, Lim S. Modeling of lophotrichous bacteria reveals key factors for swimming reorientation. Scientific Reports. Published April 20, 2022. Accessed November 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9021275/","responses":[{"text":"Bipolar flagella","correct":false,"visible":false},{"text":"Lophotrichous","correct":true,"visible":false},{"text":"Monotrichous","correct":false,"visible":false},{"text":"Petritrichous","correct":false,"visible":false},{"text":"Amphitrichous","correct":false,"visible":false}]},{"id":12674,"text":"Which of the following statements regarding somites is incorrect?","explanation":"The statement **\"44-47 pairs of somites are formed in fetal life\"** is incorrect regarding somites.\r\n\r\nSomites are blocks of paraxial mesoderm that form sequentially on both sides of the neural tube in the developing embryo. The number of somites formed during fetal life varies among species, but in humans, approximately 42-44 pairs of somites are formed, which give rise to various structures in the body. These structures include the axial skeleton, skeletal muscles, and dermis of the skin. The rate of somite formation is roughly three pairs per day during early embryonic development.","reference":"(1) Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 61, 62.\r\n(2) Dudek RW. BRS: Embryology. 6th ed. Lippincott Williams \u0026 Wilkins; 2014: 28.","responses":[{"text":"Rate of formation is 3 per day","correct":false,"visible":false},{"text":"Forms axial skeleton","correct":false,"visible":false},{"text":"44-47 pairs of somites are formed in fetal life","correct":true,"visible":false},{"text":"Involved in age determination during fetal period","correct":false,"visible":false},{"text":"Blocks of paraxial mesoderm","correct":false,"visible":false}]},{"id":12677,"text":"A high pKa value refers to which of the following?","explanation":"A high pKa value is associated with a **weak acid**. \r\nA weak acid is a substance that only partially dissociates into ions in solution and has a relatively high pKa value. The pKa value represents the pH at which half of the molecules of a weak acid are ionized and half are in their non-ionized form.\r\n\r\nA zwitterion is a molecule that has both positive and negative charges within the same molecule, typically found in amino acids and certain molecules at specific pH levels. The pKa of the amino acid side chains determines their ionization state.\r\n\r\nA strong acid is a substance that readily donates protons (H+ ions) when dissolved in water. Strong acids have very low pKa values.\r\n\r\nA cation is an ion with a positive charge, typically formed by losing electrons. It is not directly related to pKa values.\r\n\r\nAn amphoteric ion is a molecule or ion that can act as both an acid and a base, depending on the conditions. Examples include water and amino acids. The pKa value is essential in determining when these substances will act as acids or bases.","reference":"1.14: Distinguishing between pH and pKa. Chemistry LibreTexts. Published February 13, 2019. Accessed April 8, 2022. https://chem.libretexts.org/Courses/Sacramento_City_College/SCC%3A_Chem_420_-_Organic_Chemistry_I/Text/01%3A_Introduction_and_Review/1.14%3A_Distinguishing_between_pH_and_pKa","responses":[{"text":"Cation","correct":false,"visible":false},{"text":"Strong acid","correct":false,"visible":false},{"text":"Zwitter ion","correct":false,"visible":false},{"text":"Amphoteric ion","correct":false,"visible":false},{"text":"Weak acid","correct":true,"visible":false}]},{"id":12679,"text":"Which of the following statements is incorrect regarding the periosteum?","explanation":"The statement **\"It is avascular\"** is incorrect regarding the periosteum. The periosteum is a connective tissue membrane that covers the outer surface of bones, and it does contain a network of blood vessels, making it vascular.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 143.","responses":[{"text":"Has an outer layer of fibrous connective tissue","correct":false,"visible":false},{"text":"It contains osteoprogenitor cells","correct":false,"visible":false},{"text":"Contains osteoblasts","correct":false,"visible":false},{"text":"Contains type 1 collagen","correct":false,"visible":false},{"text":"It is avascular","correct":true,"visible":false}]},{"id":12681,"text":"Which of the following amino acids is not produced in the body and is therefore needed in our diet?","explanation":"Among the amino acids listed, **Phenylalanine** is not produced in the body and therefore must be obtained through our diet. Phenylalanine is an essential amino acid, which means that our body cannot synthesize it on its own, and we rely on dietary sources to meet our phenylalanine requirements.\r\n\r\nPhenylalanine is a precursor for the synthesis of several important molecules in the body, including tyrosine and various neurotransmitters. It plays a crucial role in protein synthesis and various metabolic processes.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 262.","responses":[{"text":"Glutamine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Alanine","correct":false,"visible":false},{"text":"Phenylalanine","correct":true,"visible":false},{"text":"Arginine","correct":false,"visible":false}]},{"id":12685,"text":"Which of the following correctly describes the semi-conservative model of DNA replication?","explanation":"The correct description of the semi-conservative model of DNA replication is that **daughter DNA contains one strand of parental DNA and one strand of new DNA**.\r\n\r\nIn the semi-conservative model, when DNA replicates, each newly formed double-stranded DNA molecule consists of one strand from the parental DNA (the old strand) and one newly synthesized complementary strand. This means that during replication, the original DNA molecule \"unzips,\" and each separated strand serves as a template for the synthesis of a new complementary strand. The resulting two daughter DNA molecules are identical to each other and each contains one strand from the parental DNA and one newly synthesized strand.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 415.","responses":[{"text":"Fragments of both new and old strand are dispersed in daughter DNA","correct":false,"visible":false},{"text":"Parental strands stay together as new DNA is formed","correct":false,"visible":false},{"text":"Daughter DNA contains one strand of parental and one strand of new DNA","correct":true,"visible":false},{"text":"Two entirely new daughter DNA are formed","correct":false,"visible":false},{"text":"No new strand is formed","correct":false,"visible":false}]},{"id":12688,"text":"Which of the following is a function of the sodium-potassium pump in the cell membrane?","explanation":"The sodium-potassium pump, also known as the Na+/K+ pump, plays a crucial role in maintaining cell homeostasis and various cellular functions. One of its primary functions is **controlling cell volume**.\r\n\r\nThe sodium-potassium pump is an integral membrane protein found in the plasma membrane of most animal cells. It actively transports sodium ions (Na+) out of the cell and potassium ions (K+) into the cell against their respective concentration gradients. This pump operates using energy derived from the hydrolysis of ATP (adenosine triphosphate). For each cycle of the pump, it expels three sodium ions from the cell and brings in two potassium ions, leading to the net loss of one positive charge from the intracellular space.\r\n\r\nThe sodium-potassium pump helps regulate cell volume by ensuring that the concentration of ions inside the cell is balanced. When cells accumulate too much sodium, they can swell due to the osmotic movement of water into the cell. The pump actively removes excess sodium, preventing excessive cell swelling.\r\n\r\nIn addition to regulating cell volume, the sodium-potassium pump indirectly contributes to other functions, such as maintaining the resting membrane potential, which is essential for nerve impulse transmission and muscle contraction. It also indirectly supports the transport of glucose into the cell by maintaining the electrochemical gradient necessary for secondary active transport processes.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 59.","responses":[{"text":"Decreasing heat production","correct":false,"visible":false},{"text":"Indirect transport of glucose into the cell","correct":false,"visible":false},{"text":"Synthesis of ATP","correct":false,"visible":false},{"text":"Increasing electropositive character inside the cell","correct":false,"visible":false},{"text":"Controlling cell volume","correct":true,"visible":false}]},{"id":12691,"text":"Which type of chorionic villi is involved in the exchange of nutrients and wastes between maternal and fetal blood?","explanation":"The type of chorionic villi involved in the exchange of nutrients and wastes between maternal and fetal blood is **free terminal villi**.\r\n\r\nFree terminal villi are an essential component of the placenta, a temporary organ that forms during pregnancy to facilitate the exchange of vital substances between the maternal and fetal circulatory systems. \r\n\r\nFree terminal villi are characterized by their delicate, finger-like projections covered by a layer of syncytiotrophoblasts. These structures project into the intervillous spaces of the placenta, where maternal blood circulates. The syncytiotrophoblasts are in direct contact with maternal blood, allowing for efficient exchange of nutrients, such as oxygen, glucose, amino acids, and hormones, from the maternal bloodstream to the fetal blood within the villi. Conversely, waste products like carbon dioxide and metabolic byproducts move from the fetal circulation to the maternal circulation for elimination.","reference":"Wang Y, Zhao S. Structure of the placenta. Published 2010. Accessed November 24, 2022. https://www.ncbi.nlm.nih.gov/books/NBK53256/","responses":[{"text":"Anchoring villi","correct":false,"visible":false},{"text":"Tertiary villi","correct":false,"visible":false},{"text":"Free terminal villi","correct":true,"visible":false},{"text":"Secondary villi","correct":false,"visible":false},{"text":"Primary villi","correct":false,"visible":false}]},{"id":12692,"text":"Monosaccharides that are mirror images of each other are known as?","explanation":"Monosaccharides that are mirror images of each other are known as **enantiomers**. Enantiomers are a specific type of stereoisomer, a category of isomers that have the same molecular formula and connectivity but differ in the spatial arrangement of their atoms.\r\n\r\nIn the context of monosaccharides, enantiomers arise due to the asymmetric carbon atom, also known as a chiral center, that characterizes these molecules. This chiral center gives rise to two enantiomeric forms of the same monosaccharide, often referred to as the \"right-handed\" (dextrorotary, designated as \"D\") and \"left-handed\" (levorotary, designated as \"L\") forms.\r\n\r\nAn important example of monosaccharide enantiomers is **D-glucose** and **L-glucose**. They have the same chemical formula (C6H12O6) and structural connectivity, but their spatial arrangement differs, making them non-superimposable mirror images of each other.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 84.","responses":[{"text":"Diastereoisomers","correct":false,"visible":false},{"text":"Isomers","correct":false,"visible":false},{"text":"Stereoisomers","correct":false,"visible":false},{"text":"Epimer","correct":false,"visible":false},{"text":"Enantiomers","correct":true,"visible":false}]},{"id":12693,"text":"An athlete was doing his third set of push-ups. What is his anatomical position in this situation?","explanation":"During the third set of push-ups, the athlete is in the **prone** anatomical position.\r\n\r\nThe anatomical position is a standard reference posture used in anatomy and medicine to describe the orientation of the body and its parts. In the anatomical position:\r\n- The body is upright and facing forward.\r\n- The arms are extended by the sides with the palms facing forward.\r\n- The feet are together, and the toes are pointing forward.\r\n- The individual is standing erect, with the head and eyes looking straight ahead.\r\n\r\nWhen the athlete is performing push-ups, they lie face-down on the ground, supporting their body weight with their hands and toes, and their body is in a straight line. This position is called the **prone position**, which is the opposite of the **supine position**, where the individual would be lying on their back.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 5.","responses":[{"text":"Recumbent","correct":false,"visible":false},{"text":"Prone","correct":true,"visible":false},{"text":"Supine","correct":false,"visible":false},{"text":"Lateral","correct":false,"visible":false},{"text":"Medial","correct":false,"visible":false}]},{"id":12696,"text":"Which of the following parts of the nucleus is composed of histone proteins and DNA?","explanation":"The part of the nucleus composed of **histone proteins and DNA** is called **chromatin**.\r\n\r\nChromatin is a complex of DNA and proteins found within the nucleus of eukaryotic cells. It serves several essential functions in the cell, primarily related to the organization and packaging of genetic material. Chromatin consists of long strands of DNA wrapped around histone proteins, forming a structure known as a nucleosome. These nucleosomes help condense the DNA and regulate access to specific genes.\r\n\r\nHistone proteins are positively charged, while DNA is negatively charged, creating an electrostatic attraction that facilitates the coiling and packaging of DNA. This coiling allows the long DNA strands to be efficiently packed into the relatively small nucleus of the cell. Importantly, chromatin can exist in different states, either condensed (heterochromatin) or relaxed (euchromatin), depending on the cell's needs for gene expression and replication.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 69.","responses":[{"text":"Nuclear pore","correct":false,"visible":false},{"text":"Nucleolus","correct":false,"visible":false},{"text":"Nuclear envelope","correct":false,"visible":false},{"text":"Chromatin","correct":true,"visible":false},{"text":"Nucleoplasm","correct":false,"visible":false}]},{"id":12698,"text":"The hormones epinephrine, norepinephrine, and thyroxine are derivatives of which of the following amino acids?","explanation":"**Epinephrine, norepinephrine, and thyroxine** are all derivatives of the amino acid **tyrosine**.\r\n\r\nTyrosine is a non-essential amino acid, meaning the body can synthesize it from another amino acid called phenylalanine. Tyrosine serves as a precursor for several important molecules in the body, including epinephrine, norepinephrine, and thyroxine.\r\n\r\nHere's a short overview of these hormone conversions:\r\n\r\n1. **Epinephrine and Norepinephrine:** These hormones are synthesized in the adrenal medulla, which is part of the adrenal glands located on top of the kidneys. Tyrosine is converted into **dihydroxyphenylalanine (DOPA)** by the enzyme **tyrosine hydroxylase**. DOPA is then further converted into dopamine, norepinephrine, and finally epinephrine through a series of enzymatic reactions.\r\n\r\n2. **Thyroxine (T4):** Thyroxine is one of the thyroid hormones produced by the thyroid gland. It is synthesized from tyrosine and **iodine**. Tyrosine residues within a protein called thyroglobulin are iodinated to form **monoiodotyrosine (MIT)** and **diiodotyrosine (DIT)**. These iodinated tyrosine residues then combine to form thyroxine (T4) and triiodothyronine (T3), the active thyroid hormones.","reference":"(1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 285.\r\n(2) Taylor PM, Ritchie JWA. Tissue uptake of thyroid hormone by amino acid transporters. Best Practice \u0026 Research Clinical Endocrinology \u0026 Metabolism. Published June 2007. Accessed November 25, 2022. https://linkinghub.elsevier.com/retrieve/pii/S1521690X07000231","responses":[{"text":"Valine","correct":false,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Ornithine","correct":false,"visible":false},{"text":"Tyrosine","correct":true,"visible":false},{"text":"Glycine","correct":false,"visible":false}]},{"id":12699,"text":"Which of the following cells is not derived from the neural crest cells?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 76, 308, 309.","responses":[{"text":"Odonocytes","correct":false,"visible":false},{"text":"Schwann cells","correct":false,"visible":false},{"text":"Melanocytes","correct":false,"visible":false},{"text":"Glial cells","correct":false,"visible":false},{"text":"Neurons","correct":true,"visible":false}]},{"id":15301,"text":"Which of the following biomolecules contain a polyhydroxy aldehyde or a polyhydroxy ketone in its structure?","explanation":"**Carbohydrates** are the biomolecules that contain a polyhydroxy aldehyde or a polyhydroxy ketone in their structure.\r\n\r\nCarbohydrates are one of the four major classes of biomolecules, along with proteins, nucleic acids, and lipids. They are composed of carbon (carbo-), hydrogen (-hydrate), and oxygen atoms. Carbohydrates serve various essential functions in living organisms, including providing a source of energy and serving as structural components.\r\n\r\nThe fundamental building blocks of carbohydrates are monosaccharides, which are simple sugars. Monosaccharides are characterized by having multiple hydroxyl (-OH) groups and either an aldehyde or a ketone functional group. Monosaccharides with an aldehyde functional group are called aldoses, while those with a ketone functional group are called ketoses. These polyhydroxy aldehyde or polyhydroxy ketone structures are what define carbohydrates.","reference":"Nelson DL, Cox MM, Lehninger AL. Lehninger Principles of Biochemistry. 6th ed. W.H. Freeman and Company; Macmillan Higher Education; 2012: 243.","responses":[{"text":"Proteins","correct":false,"visible":false},{"text":"Nucleic acids","correct":false,"visible":false},{"text":"Lipids","correct":false,"visible":false},{"text":"Carbohydrates","correct":true,"visible":false},{"text":"Steroids","correct":false,"visible":false}]},{"id":15302,"text":"A patient suffers some burns. The skin looks red with painful blisters. Which of the following layers of the skin are most likely to be affected?","explanation":"In the case of a patient with red, painful blisters on the skin due to burns, the **epidermis and superficial dermis** are the most likely layers to be affected.\r\n\r\nThe skin is composed of three primary layers: the epidermis, the dermis, and the subcutaneous tissue (hypodermis). Burns can affect these layers to varying degrees, with the severity of the burn categorized into first-degree, second-degree, and third-degree burns.\r\n\r\nIn this scenario, where the patient has redness and painful blisters, it indicates a **second-degree burn**, also known as a partial-thickness burn. Second-degree burns typically affect both the **epidermis** (the outermost layer of the skin) and the **superficial dermis** (the layer just beneath the epidermis).","reference":"Warby R, Maani CV. Burn classification. StatPearls. Published 2022. Accessed February 24, 2023. http://www.ncbi.nlm.nih.gov/books/NBK539773/","responses":[{"text":"Epidermis and deep dermis","correct":false,"visible":false},{"text":"Only dermis","correct":false,"visible":false},{"text":"Epidermis","correct":false,"visible":false},{"text":"Epidermis and superficial dermis","correct":true,"visible":false},{"text":"Epidermis and the entire dermis","correct":false,"visible":false}]},{"id":15303,"text":"The deficiency of which of the following lipids can result in respiratory distress syndrome in pre-term infants?","explanation":"The deficiency of **dipalmitoyl lecithin**, also known as **phosphatidylcholine**, can result in **respiratory distress syndrome (RDS)** in pre-term infants.\r\n\r\nDipalmitoyl lecithin is a critical component of lung surfactant, a complex mixture of lipids and proteins that lines the alveoli in the lungs. Lung surfactant plays a crucial role in reducing surface tension within the alveoli, preventing their collapse during expiration, and facilitating the exchange of oxygen and carbon dioxide. In premature infants, the production of lung surfactant may not be sufficient, leading to increased surface tension, alveolar collapse, and respiratory distress.\r\n\r\nRDS is characterized by difficulty in breathing, cyanosis (bluish discoloration of the skin and mucous membranes due to low oxygen levels), and other signs of respiratory distress. It is more common in premature infants because their lungs are not fully developed, and the production of lung surfactant is limited. To address RDS in pre-term infants, exogenous surfactant replacement therapy may be administered to help improve lung function and ease breathing.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 204.","responses":[{"text":"Dipalmitoyl lecithin","correct":true,"visible":false},{"text":"Cephalin","correct":false,"visible":false},{"text":"Phosphatidyl inositol","correct":false,"visible":false},{"text":"Phosphatidyl serine","correct":false,"visible":false},{"text":"Sphingomyelin","correct":false,"visible":false}]},{"id":15304,"text":"A 65-year-old man fainted and is brought to the emergency room. When he regains consciousness, he is unable to speak and has paralysis. The doctors diagnose him with cerebral artery occlusion resulting in ischemia of the left cerebral hemisphere. What type of necrosis has occurred in this patient?","explanation":"**Liquefactive necrosis** is a form of cell death characterized by the rapid breakdown of tissue structure and the formation of a liquid or viscous mass. It often occurs in tissues with high water content, such as the brain. When an ischemic event, like the occlusion of a cerebral artery, deprives brain tissue of oxygen and nutrients, the affected neurons and glial cells begin to undergo necrosis. In the brain, the tissue can liquefy, leading to the formation of a fluid-filled cystic cavity.\r\n\r\nThis type of necrosis is commonly seen in conditions involving bacterial or fungal infections, as well as in the central nervous system in response to ischemic injury, as in this patient's case. The liquefied tissue can be absorbed or walled off, but it results in the loss of normal tissue architecture and function, which may explain the patient's paralysis and speech impairment.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 43.","responses":[{"text":"Caseous necrosis","correct":false,"visible":false},{"text":"Coagulative necrosis","correct":false,"visible":false},{"text":"Fat necrosis","correct":false,"visible":false},{"text":"Liquefactive necrosis","correct":true,"visible":false},{"text":"Gangrenous necrosis","correct":false,"visible":false}]},{"id":15305,"text":"In which of the following regions of the body the normal flora is absent?","explanation":"**Blood** is the region of the body where normal flora, also known as commensal microorganisms, is typically absent.\r\n\r\nThe human body harbors a diverse community of microorganisms, collectively referred to as the normal flora or microbiota, in various regions such as the skin, oral cavity, gastrointestinal tract, respiratory tract, and genital tract. These microorganisms play crucial roles in maintaining health, aiding in digestion, and preventing the colonization of harmful pathogens.\r\n\r\nHowever, the bloodstream, under normal healthy conditions, is considered a sterile environment, meaning it should be devoid of any microorganisms, including bacteria. Any presence of microorganisms in the blood, known as bacteremia, is usually a sign of infection or a medical condition. Bacteremia can lead to serious illnesses and complications, making it a critical concern in medical practice.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 27.","responses":[{"text":"Throat","correct":false,"visible":false},{"text":"Small intestine","correct":false,"visible":false},{"text":"Large intestine","correct":false,"visible":false},{"text":"Blood","correct":true,"visible":false},{"text":"Skin","correct":false,"visible":false}]},{"id":15306,"text":"A 16-year-old boy came to the hospital with the complaint of an inability to lift his leg. Muscle testing was performed and it revealed the weakening of his muscles. What is the weakened muscle called in this movement?","explanation":"In this case, the weakened muscle responsible for lifting the leg is typically referred to as the **prime mover**.\r\n\r\nMuscle movements in the body often involve a coordinated effort of multiple muscles, each with specific roles. The prime mover, also known as the agonist, is the muscle primarily responsible for producing a specific movement or action. It contracts to initiate and carry out the desired movement. The prime mover for leg extension is often the quadriceps muscle group, specifically the rectus femoris muscle.\r\n\r\nAntagonist muscles, on the other hand, have an opposing action to the prime mover. They relax when the prime mover contracts, allowing for a smooth and controlled movement. Synergist muscles assist the prime mover in performing a specific action, while flexor and extensor muscles are generally involved in bending (flexion) and straightening (extension) of joints, respectively.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 34.","responses":[{"text":"Extensor","correct":false,"visible":false},{"text":"Flexor","correct":false,"visible":false},{"text":"Antagonist","correct":false,"visible":false},{"text":"Prime mover","correct":true,"visible":false},{"text":"Synergist","correct":false,"visible":false}]},{"id":15307,"text":"Which of the following carbohydrates modifies lipid absorption from the intestine?","explanation":"**Beta glucan** is the carbohydrate that modifies lipid absorption from the intestine.\r\n\r\nBeta glucans are a type of polysaccharide found in the cell walls of certain fungi, yeasts, algae, and cereal grains like oats and barley. These carbohydrates have been shown to have several health benefits, one of which is their ability to modify lipid (fat) absorption in the intestine.\r\n\r\nWhen beta glucans are consumed, particularly in the form of soluble fibers found in oats, they have the capacity to form a gel-like substance in the digestive tract. This gel can trap dietary fats and cholesterol, reducing their absorption from the intestine into the bloodstream. As a result, beta glucans contribute to lowering cholesterol levels and improving heart health.","reference":"Drozdowski LA, Reimer RA, Temelli F, Bell RC, Vasanthan T, Thomson ABR. β-Glucan extracts inhibit the in vitro intestinal uptake of long-chain fatty acids and cholesterol and down-regulate genes involved in lipogenesis and lipid transport in rats. The Journal of nutritional biochemistry. Published August 2010. Accessed February 24, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3833848/","responses":[{"text":"Alpha glucan","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Starch","correct":false,"visible":false},{"text":"Cellulose","correct":false,"visible":false},{"text":"Beta glucan","correct":true,"visible":false}]},{"id":15308,"text":"Which of the following bonds exists between the two monomers of a disaccharide?","explanation":"The bond that exists between the two monomers of a disaccharide is called a **glycosidic bond**.\r\n\r\nDisaccharides are carbohydrates composed of two monosaccharide molecules joined together through a condensation reaction, which involves the removal of a water molecule. During this reaction, the hydroxyl (-OH) group of one monosaccharide molecule combines with the hydrogen atom (-H) of another monosaccharide molecule, resulting in the formation of a covalent linkage known as a glycosidic bond.\r\n\r\nThis glycosidic bond can vary in its structure depending on the specific disaccharide. For example, in sucrose (table sugar), the glycosidic bond forms between glucose and fructose molecules. In lactose (the sugar found in milk), it forms between glucose and galactose molecules.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 85.","responses":[{"text":"Glycosidic bond","correct":true,"visible":false},{"text":"Ionic bond","correct":false,"visible":false},{"text":"Ether bond","correct":false,"visible":false},{"text":"Ester bond","correct":false,"visible":false},{"text":"Peptide bond","correct":false,"visible":false}]},{"id":15309,"text":"Which of the following has the highest concentration of triacylglycerol (TAG)?","explanation":"**Chylomicrons** are lipoproteins produced in the small intestine to transport dietary fats (triglycerides) from the intestine to various tissues in the body, particularly to adipose (fat) tissue. They consist predominantly of triacylglycerols and have the lowest density among lipoproteins.\r\n\r\nVery Low-Density Lipoproteins (VLDL) are another lipoprotein class that contains a significant amount of triacylglycerol and are synthesized by the liver. However, chylomicrons typically have a higher concentration of triacylglycerol compared to VLDL.\r\n\r\nApolipoproteins are protein components found in lipoproteins that play various roles in lipid transport and metabolism.\r\n\r\nHigh-Density Lipoprotein (HDL) and Low-Density Lipoprotein (LDL) contain relatively lower amounts of triacylglycerol compared to chylomicrons and VLDL. HDL is often referred to as \"good cholesterol\" because it helps remove excess cholesterol from the bloodstream, while LDL is considered \"bad cholesterol\" because it can contribute to the buildup of cholesterol in arteries.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 227.","responses":[{"text":"Low density lipoprotein","correct":false,"visible":false},{"text":"Apolipoproteins","correct":false,"visible":false},{"text":"High density lipoprotein","correct":false,"visible":false},{"text":"Very low density lipoproteins","correct":false,"visible":false},{"text":"Chylomicrons","correct":true,"visible":false}]},{"id":15310,"text":"Which of the following is not a phase 1 reaction in the process of drug metabolism?","explanation":"**Conjugation** is not a phase 1 reaction in the process of drug metabolism. Phase 1 reactions involve various chemical reactions that aim to make the drug molecule more polar or water-soluble, which facilitates its elimination from the body. These reactions are primarily oxidative or reductive in nature and serve to introduce or unmask functional groups on the drug molecule.\r\n\r\nThe other options listed—**dehydrogenation, oxidation, hydrolysis, and reduction**—are part of phase 1 drug metabolism. \r\n\r\n- **Dehydrogenation** involves the removal of hydrogen atoms from the drug molecule.\r\n- **Oxidation** is a common phase 1 reaction where drug molecules undergo oxidative transformations, often catalyzed by enzymes like cytochrome P450s.\r\n- **Hydrolysis** is the enzymatic cleavage of drug molecules by adding a water molecule, breaking chemical bonds.\r\n- **Reduction** reactions involve the addition of electrons or hydrogen atoms to the drug molecule.\r\n\r\nAfter phase 1 reactions, drugs typically undergo phase 2 reactions, which include conjugation reactions such as glucuronidation, sulfation, and methylation. These reactions further increase the water solubility of the drug, making it more easily excreted by the body.","reference":"Karen Whalen. Lippincott Illustrated Reviews: Pharmacology (South Asian Edition). (Sharma S, Velpandian T, eds.). Wolters Kluwer; 2019: 44, 45.","responses":[{"text":"Conjugation","correct":true,"visible":false},{"text":"Reduction","correct":false,"visible":false},{"text":"Oxidation","correct":false,"visible":false},{"text":"Dehydrogenation","correct":false,"visible":false},{"text":"Hydrolysis","correct":false,"visible":false}]},{"id":15313,"text":"Which of the following are essential fatty acids?","explanation":"**Linoleic acid, alpha-linolenic acid, and arachidonic acid** are essential fatty acids. These are polyunsaturated fatty acids that the body cannot synthesize on its own and must be obtained from the diet. They play crucial roles in various physiological processes and are necessary for the synthesis of important compounds, including certain types of prostaglandins and cell membrane components.\r\n\r\nLinoleic acid (an omega-6 fatty acid) and alpha-linolenic acid (an omega-3 fatty acid) are precursors for the synthesis of other essential fatty acids. For example, alpha-linolenic acid can be converted into eicosapentaenoic acid (EPA) and docosahexaenoic acid (DHA), both of which have important roles in brain function and reducing inflammation.\r\n\r\nArachidonic acid, on the other hand, is not considered an essential fatty acid because it can be synthesized in the body from linoleic acid. However, its availability from dietary sources can still be important.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 182.","responses":[{"text":"Palmitic acid and palmitoleic acid","correct":false,"visible":false},{"text":"Linoleic acid, alpha linoleic acid, and oleic acid","correct":false,"visible":false},{"text":"Arachidonic acid and linoleic acid","correct":false,"visible":false},{"text":"Linoleic acid, alpha linoleic acid, and arachidonic acid","correct":true,"visible":false},{"text":"Acetic acid, butyric acid, and capric acid","correct":false,"visible":false}]},{"id":15314,"text":"What is the class of isomers that differ in structure because of the different arrangement of functional groups around the carbon atoms called?","explanation":"**Structural isomers** are a class of isomers that differ in structure due to the distinct arrangement of functional groups around the carbon atoms. In other words, they have the same molecular formula but different connectivity or structural arrangement. This means that their atoms are bonded together in different ways.\r\n\r\nStructural isomers are sometimes called constitutional isomers because they have different constitutional arrangements. They can vary in the position of functional groups, the length of the carbon chain, or the presence of branching in the molecule. These differences in structural arrangement result in distinct chemical properties and often different biological activities.","reference":"Dow lecture slides. Foundation module. Subject: Biochemistry, Topic: Carbohydrates, Sub-topic: Structural Isomers.","responses":[{"text":"Optical isomers","correct":false,"visible":false},{"text":"Structural isomers","correct":true,"visible":false},{"text":"Chain isomers","correct":false,"visible":false},{"text":"Epimers","correct":false,"visible":false},{"text":"Enantiomers","correct":false,"visible":false}]},{"id":15315,"text":"The structure of the inhibitor is similar to the structure of the substrate in which of the following types of enzyme inhibition?","explanation":"In **competitive inhibition**, the structure of the inhibitor is indeed similar to the structure of the substrate. This type of enzyme inhibition occurs when a molecule, called the competitive inhibitor, closely resembles the substrate that the enzyme acts upon. As a result, the competitive inhibitor can bind to the enzyme's active site, effectively blocking the substrate from binding. \r\n\r\nBecause the inhibitor competes with the substrate for the active site, increasing the concentration of the substrate can overcome the inhibition. In other words, when there's a higher concentration of substrate available, it's more likely to outcompete the inhibitor for binding to the enzyme, allowing the enzyme to function normally.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 61.","responses":[{"text":"Allosteric inhibition","correct":false,"visible":false},{"text":"Irreversible inhibition","correct":false,"visible":false},{"text":"Competitive inhibition","correct":true,"visible":false},{"text":"Feedback inhibition","correct":false,"visible":false},{"text":"Non-competitive inhibition","correct":false,"visible":false}]},{"id":15316,"text":"Which of the following terms is described as the point at which the net charge on an amino acid is neutral?","explanation":"The term described as the point at which the net charge on an amino acid is neutral is the **isoelectric point**.\r\n\r\nThe isoelectric point, often abbreviated as pI, is defined as the pH at which an amino acid or a protein molecule carries no net electrical charge. In other words, it is the pH at which the number of positively charged amino groups (NH3+) equals the number of negatively charged carboxyl groups (COO-).\r\n\r\nAt the isoelectric point, amino acids or proteins are in their zwitterionic form, where they have both positive and negative charges but are overall neutral. The specific pI value varies for different amino acids and proteins due to variations in their amino acid composition and sequence.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 7.","responses":[{"text":"Dissociation point","correct":false,"visible":false},{"text":"Solubility point","correct":false,"visible":false},{"text":"Isoelectric point","correct":true,"visible":false},{"text":"Ionization point","correct":false,"visible":false},{"text":"Neutral point","correct":false,"visible":false}]},{"id":15317,"text":"Cleavage lines of the skin indicate the direction of orientation of which of the following fibers?","explanation":"Cleavage lines of the skin indicate the direction of orientation of **collagen fibers**.\r\n\r\nCollagen fibers are the main structural component of the dermis, the deeper layer of the skin. These fibers provide tensile strength and support to the skin. Cleavage lines, also known as Langer's lines or tension lines, represent the natural alignment of collagen fibers within the skin. Understanding the orientation of these lines is crucial in various medical and surgical procedures, as it affects the healing and scarring process.\r\n\r\nWhen surgical incisions or injuries are made parallel to the cleavage lines, it minimizes the disruption of collagen fibers, leading to better wound healing and reduced scarring. On the other hand, incisions made perpendicular to these lines can result in greater tension, potentially leading to more noticeable scars and slower healing.","reference":"Agache P, Humbert P, Maibach H, Fanian F, Agache P. Langer’s Lines. Agache’s Measuring the Skin. Published May 2016. Accessed February 27, 2023. https://doi.org/10.1007/978-3-319-26594-0_154-1","responses":[{"text":"Muscle fibers","correct":false,"visible":false},{"text":"Fibronectin fibers","correct":false,"visible":false},{"text":"Reticular fibers","correct":false,"visible":false},{"text":"Collagen fibers","correct":true,"visible":false},{"text":"Elastic fibers","correct":false,"visible":false}]},{"id":15318,"text":"Which of the following statements is correct regarding apoptosis?","explanation":"Apoptosis is a highly regulated process of programmed cell death that plays a crucial role in maintaining tissue homeostasis and eliminating damaged or unnecessary cells. This process is tightly controlled by a variety of proteins, including the Bcl-2 family of proteins, which can be either pro-apoptotic or anti-apoptotic.\r\n\r\n**BAX and BAK are pro-apoptotic proteins** within the Bcl-2 family. These proteins play a key role in promoting apoptosis by causing the release of cytochrome c from the mitochondria, which, in turn, activates the caspase cascade, leading to cell death. BAX and BAK are essential for initiating the intrinsic pathway of apoptosis, also known as the mitochondrial pathway. In this pathway, mitochondrial outer membrane permeabilization (MOMP) occurs, triggering the release of pro-apoptotic factors and ultimately leading to cell death.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 55.","responses":[{"text":"Apoptosis involves the inactivation of caspases","correct":false,"visible":false},{"text":"Intrinsic pathway is also known as death receptor pathway","correct":false,"visible":false},{"text":"BAX and BAK are pro-apoptotic proteins","correct":true,"visible":false},{"text":"Caspase 3 and 6 are initiator caspases","correct":false,"visible":false},{"text":"Extrinsic pathway is also known as the mitochondrial pathway","correct":false,"visible":false}]},{"id":15319,"text":"A 10-year-old boy presents to the emergency department after an injury to his leg. Upon examination, it is observed that he is unable to extend his leg. The affected movement occurs in which of the following planes?","explanation":"The affected movement in the 10-year-old boy's leg, where he is unable to extend it, occurs in the **sagittal plane**.\r\n\r\nThe body is divided into three main anatomical planes: the sagittal plane, the frontal (coronal) plane, and the transverse plane. The sagittal plane divides the body into right and left halves. Movements that occur within this plane involve flexion and extension. Flexion is a bending movement that decreases the angle between two body parts, while extension is a straightening movement that increases the angle between two body parts.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 8.","responses":[{"text":"Frontal plane","correct":false,"visible":false},{"text":"Sagittal plane","correct":true,"visible":false},{"text":"Median plane","correct":false,"visible":false},{"text":"Transverse plane","correct":false,"visible":false},{"text":"Coronal plane","correct":false,"visible":false}]},{"id":15320,"text":"Which of the following carbohydrates serves as a stored form of energy in animals?","explanation":"The carbohydrate that serves as a stored form of energy in animals is **glycogen**. Glycogen is a highly branched polysaccharide composed of glucose molecules linked together. It functions as an energy reserve in animals, particularly in the liver and muscle cells.\r\n\r\nWhen excess glucose is present in the bloodstream, it is taken up by the liver and converted into glycogen through a process called glycogenesis. Glycogen is stored in the liver and muscles and can be rapidly converted back into glucose when the body needs an immediate source of energy. This process is called glycogenolysis.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 125.","responses":[{"text":"Glycogen","correct":true,"visible":false},{"text":"Galactose","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Mannose","correct":false,"visible":false},{"text":"Sucrose","correct":false,"visible":false}]},{"id":15321,"text":"Which of the following is the appropriate property of skeletal muscles?","explanation":"The appropriate property of skeletal muscles is their **striated muscle** appearance. Skeletal muscles are composed of long, multinucleated muscle fibers that exhibit a striated (striped) appearance under a microscope. This striation is due to the repeating arrangement of contractile units called sarcomeres, which give skeletal muscle its characteristic banding pattern.\r\n\r\nSkeletal muscles are under **voluntary** control, meaning that they can be consciously controlled by the individual. This control allows for precise and coordinated movements, such as walking, running, and lifting objects.\r\n\r\nUnlike some other muscle types, skeletal muscles typically have **multiple nuclei** per muscle fiber. These nuclei are located at the periphery of the muscle fiber and contribute to the cell's ability to generate and regulate muscle contractions efficiently.\r\n\r\n**Gap junctions** are not a prominent feature of skeletal muscles. Gap junctions are more commonly found in smooth muscle tissues and cardiac muscle, where they play a role in coordinating electrical signals and contractile activity among adjacent cells.\r\n\r\nThe term **fusiform shape** does describe the general shape of skeletal muscle fibers. They are elongated and spindle-shaped, which is well-suited for generating force and facilitating movement.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 205.","responses":[{"text":"Involuntary muscle","correct":false,"visible":false},{"text":"Fusiform shape","correct":false,"visible":false},{"text":"Single nucleus","correct":false,"visible":false},{"text":"Gap junctions","correct":false,"visible":false},{"text":"Striated muscle","correct":true,"visible":false}]},{"id":15322,"text":"A patient is diagnosed with the dislocation of a synovial joint in the upper limb. Which of the following is an inappropriate statement regarding the synovial type of joints?","explanation":"In the context of synovial joints, the statement that \"they are immobile\" is inappropriate. Synovial joints are actually known for their mobility and flexibility, and they are the most common type of joint in the human body designed precisely for that purpose.\r\n\r\nSynovial joints are characterized by several key features, including the presence of a synovial cavity, articular cartilage covering the articulating surfaces, and a synovial membrane that secretes synovial fluid. These features collectively allow for smooth and frictionless movement between the bone ends within the joint.\r\n\r\nAdditionally, synovial joints are reinforced by ligaments, both intra-capsular (inside the joint capsule) and extra-capsular (outside the joint capsule), which help stabilize the joint while permitting a wide range of motion. The combination of these structural elements, including the synovial cavity and articular cartilage, enables the mobility and flexibility that are characteristic of synovial joints.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 26.","responses":[{"text":"They possess intra-capsular and extra-capsular ligaments","correct":false,"visible":false},{"text":"They are immobile","correct":true,"visible":false},{"text":"They have a synovial cavity","correct":false,"visible":false},{"text":"They have articulating hyaline cartilage","correct":false,"visible":false},{"text":"They have fibrous tissue","correct":false,"visible":false}]},{"id":15323,"text":"Ammonia is converted into which of the following non-toxic amino acids?","explanation":"Ammonia is converted into **glutamine**, which is a non-toxic amino acid and serves as a critical component of the body's ammonia detoxification process.\r\n\r\nIn the process of ammonia detoxification, ammonia combines with glutamate, another amino acid, to form glutamine. Glutamine is a non-toxic amino acid that can be safely transported in the bloodstream to various tissues, including the liver, where it can be further processed to eliminate ammonia from the body.\r\n\r\nThe conversion of ammonia into glutamine is carried out by the enzyme **glutamine synthetase**, primarily in the liver and brain. This enzymatic reaction ensures that excess ammonia is safely handled and does not accumulate to harmful levels in the body.","reference":"Mohiuddin SS, Khattar D. Biochemistry, ammonia. StatPearls. Published 2022. Accessed February 27, 2023. http://www.ncbi.nlm.nih.gov/books/NBK541039/","responses":[{"text":"Glutamate","correct":false,"visible":false},{"text":"Aspargine","correct":false,"visible":false},{"text":"Histidine","correct":false,"visible":false},{"text":"Glutamine","correct":true,"visible":false},{"text":"Aspartate","correct":false,"visible":false}]},{"id":15324,"text":"Which of the following solutions would cause red blood cells to shrink?","explanation":"The solution that would cause red blood cells to shrink is **1.0% NaCl**.\r\n\r\nRed blood cells, also known as erythrocytes, are sensitive to changes in the osmolarity of their environment. Osmolarity refers to the concentration of solute particles in a solution. When red blood cells are placed in a hypertonic solution, where the solute concentration is higher outside the cell than inside, water molecules tend to move out of the cells through a process called osmosis.\r\n\r\nIn this scenario, a 1.0% NaCl solution represents a hypertonic solution. The high concentration of salt (NaCl) outside the red blood cells creates an osmotic gradient that draws water out of the cells. As water leaves the cells, they lose volume and become shriveled or crenated. This is because the osmotic movement of water aims to equalize the solute concentrations on both sides of the cell membrane.\r\n\r\nConversely, in a hypotonic solution where the solute concentration is lower outside the cell, red blood cells may swell and burst, a condition known as hemolysis. The 0.9% NaCl solution, often referred to as normal saline, is isotonic to red blood cells and does not cause them to shrink or swell, making it compatible with intravenous administration without damaging the cells.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 311.","responses":[{"text":"0.1% NaCl","correct":false,"visible":false},{"text":"0.5% NaCl","correct":false,"visible":false},{"text":"0.3% NaCl","correct":false,"visible":false},{"text":"0.9% NaCl","correct":false,"visible":false},{"text":"1.0% NaCl","correct":true,"visible":false}]},{"id":15325,"text":"Gangliosides are complex sphingolipids mostly found in which of the following cells of the body?","explanation":"**Gangliosides** are complex sphingolipids primarily found in neurons of the body, particularly in the **central nervous system.**\r\n\r\nGangliosides are a class of glycosphingolipids that contain sialic acid (a type of sugar) in their structure. They are most abundant in neural tissue, where they play crucial roles in various neuronal functions. These complex lipids are primarily located in the outer leaflet of the neuronal cell membrane.\r\n\r\nOne of the key functions of gangliosides is their involvement in cell signaling and recognition. They are essential for cell-to-cell communication in the nervous system, as they participate in processes such as cell adhesion, signal transduction, and neuronal development. Gangliosides also serve as receptors for certain pathogens and toxins, mediating their binding and internalization into neurons.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 209.","responses":[{"text":"Oligodendrocytes","correct":false,"visible":false},{"text":"Neurons","correct":false,"visible":false},{"text":"Ganglion cells of central nervous system","correct":true,"visible":false},{"text":"All cells of the body","correct":false,"visible":false},{"text":"Ganglion cells of peripheral nervous system","correct":false,"visible":false}]},{"id":15326,"text":"Which of the following minerals is required to maintain the membrane potential?","explanation":"**Sodium** is the mineral required to maintain the membrane potential in cells. The maintenance of a resting membrane potential is essential for normal cell function, especially in neurons and muscle cells. This potential difference across the cell membrane is established and maintained by the selective movement of ions, primarily sodium (Na+), potassium (K+), and chloride (Cl-), across the cell membrane.\r\n\r\nIn a resting state, the cell membrane is more permeable to potassium ions than sodium ions. This results in a higher concentration of sodium ions outside the cell and a higher concentration of potassium ions inside the cell. The sodium-potassium pump, a specialized protein found in the cell membrane, actively transports three sodium ions out of the cell and two potassium ions into the cell against their respective concentration gradients. This pump consumes energy in the form of ATP to maintain this ion balance.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 408.","responses":[{"text":"Sodium","correct":true,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Fluorine","correct":false,"visible":false},{"text":"Magnesium","correct":false,"visible":false},{"text":"Chlorine","correct":false,"visible":false}]},{"id":15327,"text":"Which of the following vitamins acts as a coenzyme?","explanation":"**Vitamin B complex** is a group of water-soluble vitamins that play essential roles as coenzymes in various biochemical reactions within the body. These vitamins include B1 (thiamine), B2 (riboflavin), B3 (niacin), B5 (pantothenic acid), B6 (pyridoxine), B7 (biotin), B9 (folic acid), and B12 (cobalamin). \r\n\r\nCoenzymes are molecules that assist enzymes in catalyzing specific chemical reactions. They are crucial for the proper functioning of many metabolic pathways. In the case of the B-complex vitamins, they often serve as coenzymes in reactions involving the metabolism of carbohydrates, proteins, and fats.\r\n\r\nFor instance, vitamin B1 (thiamine) acts as a coenzyme in the conversion of glucose into energy in the form of ATP. Vitamin B2 (riboflavin) is a component of coenzymes involved in various redox reactions. Vitamin B3 (niacin) is essential for the synthesis of coenzymes that participate in the oxidation of glucose and fatty acids.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 377, 396.","responses":[{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin B12 only","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin B complex","correct":true,"visible":false}]},{"id":15328,"text":"A group of friends visited a cold hilly area during their winter vacations. Which of the following physiological responses is most likely to occur in their body?","explanation":"When a group of friends visits a cold hilly area during their winter vacations, their bodies will undergo various physiological responses to maintain core body temperature and adapt to the cold environment. One of the most likely responses is **shivering of skeletal muscles**.\r\n\r\nShivering is an involuntary muscular response triggered by the body's temperature regulation system. In cold conditions, the body attempts to generate heat to maintain its core temperature. Shivering involves rapid contractions and relaxations of skeletal muscles, which produce heat as a byproduct of muscular activity. This heat production helps to counteract the loss of body heat to the cold surroundings, ultimately preserving the body's core temperature within a normal range.\r\n\r\nAdditionally, other responses like **vasoconstriction** (not vasodilation), where blood vessels narrow to reduce heat loss from the skin's surface, and **piloerection** (hair standing on end) may also occur to conserve heat. These responses collectively aid in the body's effort to maintain thermal balance and protect against hypothermia in the cold environment.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 906, 907.","responses":[{"text":"Shivering of skeletal muscles","correct":true,"visible":false},{"text":"Increased sweating","correct":false,"visible":false},{"text":"Vasodilation","correct":false,"visible":false},{"text":"Relaxation of piloerector muscles","correct":false,"visible":false},{"text":"Relaxation of skeletal muscles","correct":false,"visible":false}]},{"id":15329,"text":"Which of the following best explains why obligate anaerobes cannot grow in the presence of oxygen?","explanation":"Obligate anaerobes cannot grow in the presence of oxygen primarily because they lack the enzymes **superoxide dismutase and catalase**. These enzymes are crucial for dealing with the toxic byproducts of oxygen metabolism, such as superoxide radicals and hydrogen peroxide.\r\n\r\n**Superoxide dismutase** converts superoxide radicals into oxygen and hydrogen peroxide, while **catalase** further breaks down hydrogen peroxide into harmless water and oxygen. In the absence of these enzymes, the presence of oxygen leads to the accumulation of these toxic molecules within the bacterial cells, causing damage to essential cellular components like proteins and DNA.","reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018:  16.","responses":[{"text":"They lack superoxide dismutase and catalase","correct":true,"visible":false},{"text":"They possess defences to make aerobic life possible","correct":false,"visible":false},{"text":"They require oxygen for ATP generation","correct":false,"visible":false},{"text":"They can not use the fermentation pathway for ATP generation","correct":false,"visible":false},{"text":"They need ATP produced by host cells for survival","correct":false,"visible":false}]},{"id":15330,"text":"When preparing a tissue for routine light microscopic study, which procedure is carried out once the tissue proteins are fixed in a solution of fixatives and cross-linking compounds?","explanation":"Once tissue proteins are fixed in a solution of fixatives and cross-linking compounds during the preparation of a tissue for routine light microscopic study, the next step is **dehydration**.\r\n\r\nDehydration is a critical step in the tissue preparation process. It involves the removal of water from the tissue gradually by passing it through a series of alcohol solutions of increasing concentration. This is typically done to replace the water within the tissue with alcohol, as alcohol is miscible with both water and the embedding medium used in the subsequent step.\r\n\r\nAfter dehydration, the tissue is ready for **embedding**, where it is infiltrated with a medium that will solidify, allowing for the creation of thin sections for microscopic examination. Once embedded, the tissue can be cut into thin slices, stained, and mounted on slides for observation under a light microscope.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 15.","responses":[{"text":"Embedding","correct":false,"visible":false},{"text":"Cleaving","correct":false,"visible":false},{"text":"Dehydration","correct":true,"visible":false},{"text":"Fixation","correct":false,"visible":false},{"text":"Staining","correct":false,"visible":false}]}
]

export default a